};

// ========== 状态变量 ==========
let sceneMode = 'day';
let currentScenario = 'normalDay';
let demoMode = false;
let currentPage = 'scene';
let els = {};
let refreshTimer = null;
let debugSliding = {};
let debugLockUntil = {};
let rpcPending = { device01: {}, device02: {} };

// 历史数据缓存（按设备分开）
const historyBuffer = {
  device01: {
    temperature: [], airHumidity: [], soilHumidity: [], lightIntensity: [],
